import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        reverseAdj[v].push([u, w]);
    }

    // dist[u][0] = distance to u without using switch
    // dist[u][1] = distance to u with using switch at some point
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    const heap = new MinPriorityQueue({
        priority: (item) => item.cost
    });
    heap.enqueue({ node: 0, usedSwitch: 0, cost: 0 });

    while (!heap.isEmpty()) {
        const { node: u, usedSwitch, cost } = heap.dequeue().element;
        if (u === n - 1) {
            return cost;
        }
        if (cost > dist[u][usedSwitch]) {
            continue;
        }

        // Normal edges
        for (const [v, w] of adj[u]) {
            if (dist[v][usedSwitch] > cost + w) {
                dist[v][usedSwitch] = cost + w;
                heap.enqueue({ node: v, usedSwitch, cost: cost + w });
            }
        }

        // If not used switch yet, try to use it
        if (usedSwitch === 0) {
            for (const [v, w] of reverseAdj[u]) {
                const newCost = cost + 2 * w;
                if (dist[v][1] > newCost) {
                    dist[v][1] = newCost;
                    heap.enqueue({ node: v, usedSwitch: 1, cost: newCost });
                }
            }
        }
    }

    const res = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return res === Infinity ? -1 : res;
}

